1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const COMPONENT_BLOCK_PREMIUM = 60;
4	
5	const BASE_PREMIUMS: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune"]);
14	
15	function calculateBasePremium(items: any[]): number {
16	  const counts: Record<string, number> = {};
17	  for (const item of items) {
18	    if (COMPONENT_TYPES.has(item.type)) {
19	      counts[item.type] = (counts[item.type] || 0) + 1;
20	    }
21	  }
22	  let premium = 0;
23	  for (const item of items) {
24	    if (COMPONENT_TYPES.has(item.type)) {
25	      continue;
26	    }
27	    premium += BASE_PREMIUMS[item.type];
28	  }
29	  for (const [type, count] of Object.entries(counts)) {
30	    if (count === 3) {
31	      premium += COMPONENT_BLOCK_PREMIUM;
32	    } else {
33	      premium += count * BASE_PREMIUMS[type];
34	    }
35	  }
36	  return premium;
37	}
38	
39	export function processScenario(scenario: any): any {
40	  const results = scenario.steps.map((step: any) => {
41	    const basePremium = calculateBasePremium(step.items);
42	    const premium = basePremium + basePremium * FIRST_INSURANCE_SURCHARGE_RATE + PROCESSING_FEE;
43	    return { premium };
44	  });
45	  return { results };
46	}
